sql:
SELECT role, experience_level, COUNT(*) AS count
FROM crew_members
GROUP BY role, experience_level;

SELECT races.event_name, races.boat_class, boats.owner_name
FROM races
INNER JOIN boats ON races.boat_class = boats.boat_class;

SELECT DISTINCT boats.boat_class, boats.owner_name
FROM boats
INNER JOIN crew_members ON boats.boat_id = crew_members.boat_id;

SELECT r.boat_class, AVG(r.race_distance) AS average_race_distance
FROM races AS r
GROUP BY r.boat_class;

SELECT crew_members.crew_id, crew_members.crew_name, crew_members.boat_id, boats.boat_class, boats.owner_name
FROM crew_members
JOIN boats ON crew_members.boat_id = boats.boat_id;

SELECT event_name, race_date, race_location, race_type, weather_conditions, race_distance, race_start_time, race_end_time
FROM races
WHERE boat_class = 'Laser Radial';
